import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { adminGuard } from './core/guards/admin.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// See flow-meta.ts for authoring rules. Every navigable state is URL-addressable:
//   movement type via ?type=IN|OUT|TRANSFER, audit filters via ?itemId&from&to,
//   admin create via ?form=new, edit via /:id/edit, item detail via /items/:id.
export const routes: Routes = ([
  { path: '', redirectTo: 'login', pathMatch: 'full' },

  {
    path: 'login',
    loadComponent: () =>
      import('./features/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { flowId: 'login', node: 'login', entry: true, edgesTo: ['signup', 'items'], label: 'Login' } },
  },
  {
    path: 'signup',
    loadComponent: () =>
      import('./features/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { flowId: 'signup', node: 'signup', edgesTo: ['login', 'items'], label: 'Sign up' } },
  },

  {
    path: '',
    loadComponent: () =>
      import('./shared/storefront-layout.component').then((m) => m.StorefrontLayoutComponent),
    children: [
      {
        path: 'items',
        loadComponent: () =>
          import('./features/items/items-list.component').then((m) => m.ItemsListComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'items', node: 'items', showInNavbar: true, label: 'Items', scope: 'all', edgesTo: ['item-detail', 'movement-new', 'admin-items'] } },
      },
      {
        path: 'items/:id',
        loadComponent: () =>
          import('./features/items/item-detail.component').then((m) => m.ItemDetailComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'item-detail', node: 'item-detail', label: 'Item detail', edgesTo: ['movement-new', 'admin-item-edit'] } },
      },
      {
        path: 'movements/new',
        loadComponent: () =>
          import('./features/movements/movement-form.component').then((m) => m.MovementFormComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'movement-new', node: 'movement-new', showInNavbar: true, label: 'Record Movement', scope: 'all', edgesTo: ['item-detail'] } },
      },
      {
        path: 'movements',
        loadComponent: () =>
          import('./features/movements/audit-log.component').then((m) => m.AuditLogComponent),
        canActivate: [adminGuard],
        data: { flow: { flowId: 'audit-log', node: 'audit-log', showInNavbar: true, label: 'Audit Log', scope: 'admin' } },
      },
      {
        path: 'reports/low-stock',
        loadComponent: () =>
          import('./features/reports/low-stock.component').then((m) => m.LowStockComponent),
        canActivate: [adminGuard],
        data: { flow: { flowId: 'low-stock', node: 'low-stock', showInNavbar: true, label: 'Low-Stock Report', scope: 'admin', edgesTo: ['movement-new'] } },
      },
      {
        path: 'admin/items',
        loadComponent: () =>
          import('./features/admin/admin-items.component').then((m) => m.AdminItemsComponent),
        canActivate: [adminGuard],
        data: { flow: { flowId: 'admin-items', node: 'admin-items', showInNavbar: true, label: 'Manage Items', scope: 'admin', edgesTo: ['admin-item-edit'] } },
      },
      {
        path: 'admin/items/:id/edit',
        loadComponent: () =>
          import('./features/admin/admin-items.component').then((m) => m.AdminItemsComponent),
        canActivate: [adminGuard],
        data: { flow: { flowId: 'admin-item-edit', node: 'admin-item-edit', label: 'Edit Item', edgesTo: ['admin-items'] } },
      },
      {
        path: 'admin/locations',
        loadComponent: () =>
          import('./features/admin/admin-locations.component').then((m) => m.AdminLocationsComponent),
        canActivate: [adminGuard],
        data: { flow: { flowId: 'admin-locations', node: 'admin-locations', showInNavbar: true, label: 'Manage Locations', scope: 'admin', edgesTo: ['admin-location-edit'] } },
      },
      {
        path: 'admin/locations/:id/edit',
        loadComponent: () =>
          import('./features/admin/admin-locations.component').then((m) => m.AdminLocationsComponent),
        canActivate: [adminGuard],
        data: { flow: { flowId: 'admin-location-edit', node: 'admin-location-edit', label: 'Edit Location', edgesTo: ['admin-locations'] } },
      },
      {
        path: 'admin/settings',
        loadComponent: () =>
          import('./features/admin/admin-settings.component').then((m) => m.AdminSettingsComponent),
        canActivate: [adminGuard],
        data: { flow: { flowId: 'admin-settings', node: 'admin-settings', showInNavbar: true, label: 'Settings', scope: 'admin' } },
      },
    ],
  },

  { path: '**', redirectTo: 'items' },
] satisfies FlowRoute[]) as Routes;
